package ludens.build.compose.settings

import ludens.build.compose.configuration.LudensResolvedSettingsPresetConfiguration
import org.gradle.api.DefaultTask
import org.gradle.api.file.RegularFileProperty
import org.gradle.api.provider.Property
import org.gradle.api.tasks.Input
import org.gradle.api.tasks.OutputFile
import org.gradle.api.tasks.TaskAction

/**
 * Generates the Kotlin object consumed by the app as the default settings preset.
 *
 * The generated file is compiled into `commonMain` and exposes constants such as
 * `presetName` and `preset.toolMuted`.
 */
abstract class SettingsPresetGenerationTask : DefaultTask() {

    /** Kotlin package used by the generated source file. */
    @get:Input
    abstract val packageName: Property<String>

    /** Top-level object name written to the generated Kotlin source. */
    @get:Input
    abstract val objectName: Property<String>

    /** Resolved preset configuration. */
    @get:Input
    abstract val presets: Property<LudensResolvedSettingsPresetConfiguration>

    /** Output file that will contain the generated Kotlin source. */
    @get:OutputFile
    abstract val outputFile: RegularFileProperty

    @TaskAction
    fun generate() {
        // Build the final Kotlin source from the resolved preset values.
        with(presets.get()) {

            val content = buildString {
                appendLine("package ${packageName.get()}")
                appendLine()
                appendLine("// Autogenerated file. Do not edit manually.")
                appendLine()
                appendLine("object ${objectName.get()} {")
                appendLine("    const val presetName: String = \"${escape(presetName)}\"")
                appendLine()
                appendLine("    object preset {")
                appendLine("        const val toolMuted: Boolean = $toolMuted")
                appendLine("        const val toolShowFPS: Boolean = $toolShowFps")
                appendLine("        const val toolUseWebgl: Boolean = $toolUseWebgl")
                appendLine("        const val controlEnabled: Boolean = $controlEnabled")
                appendLine("        const val controlAlpha: Float = ${floatLiteral(controlAlpha)}")
                appendLine("        const val actionEnabled: Boolean = $actionEnabled")
                appendLine("        const val actionItems: String = \"${escape(actionItems)}\"")
                appendLine("        const val systemTheme: String = \"${escape(systemTheme)}\"")
                appendLine("        const val systemLanguage: String = \"${escape(systemLanguage)}\"")
                appendLine("    }")
                appendLine("}")
            }

            outputFile.get().asFile.apply {
                parentFile.mkdirs()
                writeText(content)
            }
        }


    }

    private fun floatLiteral(value: Float): String {
        val text = value.toString()
        return if (text.endsWith("f")) text else "${text}f"
    }

    private fun escape(value: String): String {
        return value.replace("\\", "\\\\").replace("\"", "\\\"")
    }
}
